head.script:
scwin.saveflag = "N"; 		// 저장상태구분
scwin.sumAmtAll = 0;			//매출합계금액
scwin.cashSellAmt = 0;		//현금매출액 		
scwin.susRecvSellRtnDrAmt = 0;//가수금매출환불차변금액
scwin.susRecvSellAmt = 0;		//가수금매출금액
scwin.susRecvSellAmtTot = 0;	//가수금매출금액+가수금매출환불차변금액
scwin.pldgAmt = 0;			//담보금액
scwin.egain = 0;				//잡이익
scwin.initamtGrtRtnDrAmt = 0;	//선수금보증환불차변금액
scwin.cashRtnAmt = 0;			//현금환불금액

scwin.susRecvInitamtClsCd = "01";
scwin.p_summary = "";

/*수령거래처매출정보조회 로직 사용안함 제외처리 (f_RetrieveSellingInfo) */

scwin.onpageload = function () {

    scwin.params = $c.data.getParameter();
    console.log(scwin.params);

    let pchsClntNo = scwin.params.param1;
    let ctrtNo = scwin.params.param2;
    let eqCd = scwin.params.param3;
    let crn = scwin.params.param4;
    let oilSubsidyPayStdDt = scwin.params.param5;
    let calnDocDrawDt = scwin.params.param6;
    let seq = scwin.params.param7;
    let taxnClsCd = scwin.params.param8;
    let certiNo = scwin.params.param11;
    let costItemCd = scwin.params.param12;

    //공통코드
    const codeOptions = [
        { grpCd: "FS900", compID: "acb_lc_costItemCd" },      //부가세/ 매출항목구분
    ];

    console.log(codeOptions);
    $c.data.setCommonCode(codeOptions);

    //데이타 mpa에 세팅
    dma_queryCondition.set("pchsClntNo", pchsClntNo);
    dma_queryCondition.set("ctrtNo", ctrtNo);
    dma_queryCondition.set("eqCd", eqCd);
    dma_queryCondition.set("crn", crn);
    dma_queryCondition.set("oilSubsidyPayStdDt", oilSubsidyPayStdDt);
    dma_queryCondition.set("calnDocDrawDt", calnDocDrawDt);
    dma_queryCondition.set("seq", seq);
    dma_queryCondition.set("taxnClsCd", taxnClsCd);
    dma_queryCondition.set("certiNo", certiNo);
    dma_queryCondition.set("costItemCd", costItemCd);
    //서비스조회
    $c.sbm.execute(sbm_retrieve);
};


scwin.onUdcCompleted = function () {

};

scwin.ondataload = function () {
    acb_lc_costItemCd.setValue(scwin.params.param12)
}


//매출증빙내역 setting
scwin.f_setsellingEvidence = function () {

    lay_slipNo.setValue(ds_sellingEvidence.getCellData(0, "slipNo"));						// 전표번호
    lay_setoffSlipNo.setValue(ds_sellingEvidence.getCellData(0, "setoffSlipNo"));						// 상계전표번호			
    lay_bilgLodept.setValue(ds_sellingEvidence.getCellData(0, "bilgLodeptCd"));						// 청구부서
    ica_ed_slipDt.setValue(ds_sellingEvidence.getCellData(0, "slipDt"));						// 전표일자
    lay_spplyAmt.setValue(ds_sellingEvidence.getCellData(0, "spplyAmt"));						// 공급금액
    lay_vatAmt.setValue(ds_sellingEvidence.getCellData(0, "vatAmt"));						// 부가세금액
    lay_sumAmt.setValue(ds_sellingEvidence.getCellData(0, "sumAmt"));						// 합계금액
    ed_summary.setValue(ds_sellingEvidence.getCellData(0, "summary"));						// 적요

    lay_crn.setValue(ds_sellingEvidence.getCellData(0, "crn"));                                  // 사업자번호
    lay_busiNm.setValue(ds_sellingEvidence.getCellData(0, "clntNm"));						//거래처명
    ica_ed_spplyDt.setValue(ds_sellingEvidence.getCellData(0, "spplyDt"));						// 공급일자
    ed_bilgClnt.setValue(ds_sellingEvidence.getCellData(0, "clntNo"));						// 청구거래처		
    ica_ed_postDt.setValue(ds_sellingEvidence.getCellData(0, "postDt"));						// 회계처리일자
    //acb_lc_costItemCd.setValue(ds_sellingEvidence.getCellData(0, "costItemCd"          ));
};

//저장
scwin.btn_save_onclick = async function (e) {

    //필수입력항목 체크
    if (!await $c.gus.cfValidate([ica_ed_spplyDt, ed_summary]))
        return;

    //수금 내역 금액 검증
    if (!scwin.f_chkAmt()) {
        await $c.gus.cfAlertMsg("수금정보의 금액항목 오류입니다.\n다시 확인하십시오.");
        return;
    }

    if (!await $c.win.confirm(MSG_CM_CRM_001)) return;

    // asis 는 undefined 이나 tobe는 ''로 들어옴 
    // if (ds_sellingEvidence.getCellData(0, "setoffSlipNo") != "") {
    if (ds_sellingEvidence.getTotalRow() == 0 || ds_sellingEvidence.getCellData(0, "setoffSlipNo") != "") {
        await $c.gus.cfAlertMsg("상계전표번호가 존재합니다. 상계 취소 후 다시 작업하여 주십시오.");
        return;
    }

    scwin.f_SetDataSet(); // 저장 or 삭제 DataSet Setting   
    $c.sbm.execute(sbm_save);
};

//저장 callback
scwin.sbm_save_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        if (ds_sellingEvidence.getRowCount() > 0) {
            $c.gus.cfEnableBtnOnly([btn_del]);
            $c.gus.cfDisableBtnOnly([btn_save]);
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.saveflag = "C";
            $c.win.closePopup();

        } else {
            scwin.saveflag = "N";
        }
    }

};

// 금액계산 입력시 검증
scwin.f_chkAmt = function () {

    //if(sumAmtAll == cashSellAmt+susRecvSellRtnDrAmt+susRecvSellAmt+pldgAmt-egain-((initamtGrtRtnDrAmt+susRecvSellRtnDrAmt+cashRtnAmt)/2)){
    if (scwin.sumAmtAll == scwin.cashSellAmt + scwin.susRecvSellRtnDrAmt
        + scwin.susRecvSellAmt + scwin.pldgAmt - scwin.egain
        - ((scwin.initamtGrtRtnDrAmt + scwin.susRecvSellRtnDrAmt + scwin.cashRtnAmt) / 2)) {
        return true;
    } else {
        return false;
    }
};

//조회callback 처리
scwin.sbm_retrieve_submitdone = async function () {

    if (ds_sellingEvidence.getTotalRow() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    } else {

        scwin.f_setsellingEvidence(); // 매출증빙 내역 setting처리

        if (ds_sellingEvidence.getCellData(0, "slipNo") != null && ds_sellingEvidence.getCellData(0, "slipNo") != "") {
            ica_ed_spplyDt.setReadOnly(true)
            ica_ed_slipDt.setReadOnly(true);
            $c.gus.cfEnableObj(ed_summary, false);
        } else {
            ed_summary.getValue(scwin.p_summary);
			ica_ed_spplyDt.setReadOnly(false);
			ica_ed_slipDt.setReadOnly(false);
			$c.gus.cfEnableObj(ed_summary,true);
        }
    }

    if (ds_sellingEvidence.getRowCount() > 0 && ds_sellingEvidence.getCellData(0, "slipNo") != "") {
        $c.gus.cfEnableBtnOnly([btn_del]);
        $c.gus.cfDisableBtnOnly([btn_save]);
        scwin.saveflag = "E";
    } else {
        $c.gus.cfEnableBtnOnly([btn_save]);
        $c.gus.cfDisableBtnOnly([btn_del]);
        scwin.saveflag = "N";
    }
};

//삭제
scwin.btn_del_onclick = async function (e) {

    if (ds_sellingEvidence.getCellData(0, "postDt") != "") {

        let confirm = await $c.win.confirm("회계처리되었습니다. 삭제하시겠습니까?")
        if (!confirm) {
            return;
        }
    }

    scwin.f_SetDataSet();  //저장 or 삭제 DataSet Setting
    $c.sbm.execute(sbm_del);
};

//삭제 callback
scwin.sbm_del_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg(MSG_CM_INF_004);
        scwin.saveflag = "D";
        $c.win.closePopup();
    }
};

//Save DataSet Setting
scwin.f_SetDataSet = function () {

    dma_queryCondition.setEmptyValue();

    ds_sellingEvidenceSave.insertRow();
    ds_sellingEvidenceSave.setCellAllData(0, "choice", "T");
    ds_sellingEvidenceSave.setCellAllData(0, "slipDt", ica_ed_slipDt.getValue());
    ds_sellingEvidenceSave.setCellAllData(0, "slipNo", ds_sellingEvidence.getCellData(0, "slipNo"));
    ds_sellingEvidenceSave.setCellAllData(0, "summary", ed_summary.getValue());
    ds_sellingEvidenceSave.setCellAllData(0, "spplyDt", ds_sellingEvidence.getCellData(0, "spplyDt"));
    ds_sellingEvidenceSave.setCellAllData(0, "clntNo", ds_sellingEvidence.getCellData(0, "clntNo"));
    ds_sellingEvidenceSave.setCellAllData(0, "crn", ds_sellingEvidence.getCellData(0, "crn"));
    ds_sellingEvidenceSave.setCellAllData(0, "postDt", ica_ed_postDt.getValue());
    ds_sellingEvidenceSave.setCellAllData(0, "collMoneyAcctDeptCd", ds_sellingEvidence.getCellData(0, "acctDeptCd"));
    ds_sellingEvidenceSave.setCellAllData(0, "bilgLodeptCd", ds_sellingEvidence.getCellData(0, "bilgLodeptCd"));
    ds_sellingEvidenceSave.setCellAllData(0, "acctDeptCd", ds_sellingEvidence.getCellData(0, "acctDeptCd"));
    ds_sellingEvidenceSave.setCellAllData(0, "bilgClntNo", ds_sellingEvidence.getCellData(0, "clntNo"));
    ds_sellingEvidenceSave.setCellAllData(0, "bilgClntNm", ds_sellingEvidence.getCellData(0, "clntNm"));

    ds_sellingEvidenceSave.setCellAllData(0, "payAmt", ds_sellingEvidence.getCellData(0, "payAmt"));
    ds_sellingEvidenceSave.setCellAllData(0, "drvAdjmAmt", ds_sellingEvidence.getCellData(0, "drvAdjmAmt"));
    ds_sellingEvidenceSave.setCellAllData(0, "ctrtNo", ds_sellingEvidence.getCellData(0, "ctrtNo"));
    ds_sellingEvidenceSave.setCellAllData(0, "eqCd", ds_sellingEvidence.getCellData(0, "eqCd"));
    ds_sellingEvidenceSave.setCellAllData(0, "oilSubsidyPayStdDt", ds_sellingEvidence.getCellData(0, "oilSubsidyPayStdDt"));
    ds_sellingEvidenceSave.setCellAllData(0, "calnDocDrawDt", ds_sellingEvidence.getCellData(0, "calnDocDrawDt"));
    ds_sellingEvidenceSave.setCellAllData(0, "seq", ds_sellingEvidence.getCellData(0, "seq"));
    ds_sellingEvidenceSave.setCellAllData(0, "ttaxnClsCd", ds_sellingEvidence.getCellData(0, "ttaxnClsCd"));

    ds_sellingEvidenceSave.setCellAllData(0, "crcCd", "KRW");
    ds_sellingEvidenceSave.setCellAllData(0, "receptClsCd", "01");		// 영수
    ds_sellingEvidenceSave.setCellAllData(0, "evidRglClsCd", "01");		//세금계산서 상태 : 01 '정상', 02 '적자', 99 '삭제'
    ds_sellingEvidenceSave.setCellAllData(0, "certiNo", ds_sellingEvidence.getCellData(0, "certiNo"));		//거래명세서건수
    ds_sellingEvidenceSave.setCellAllData(0, "certiCnt", "1");		//거래명세서건수
    ds_sellingEvidenceSave.setCellAllData(0, "bilgAmt", "0");
    ds_sellingEvidenceSave.setCellAllData(0, "bilgAmtFcrc", "0");
    ds_sellingEvidenceSave.setCellAllData(0, "fcrcBilgAmt", "0");
    ds_sellingEvidenceSave.setCellAllData(0, "spplyAmt", ds_sellingEvidence.getCellData(0, "spplyAmt"));
    ds_sellingEvidenceSave.setCellAllData(0, "vatAmt", ds_sellingEvidence.getCellData(0, "vatAmt"));
    ds_sellingEvidenceSave.setCellAllData(0, "fmlaPatternCd", "01");
    ds_sellingEvidenceSave.setCellAllData(0, "fmlaClsCd", "01");
    if (ds_sellingEvidence.getCellAllData(0, "dcsnClsCd") == "0") {
        ds_sellingEvidence.setCellAllData(0, "dcsnClsCd", "3")
    }
    ds_sellingEvidenceSave.setCellAllData(0, "dcsnClsCd", ds_sellingEvidence.getCellData(0, "dcsnClsCd"));
    ds_sellingEvidenceSave.setCellAllData(0, "taxnClsCd", '03');		// 부가세 구분 : 기타
    ds_sellingEvidenceSave.setCellAllData(0, "slipKndCd", "F05");
    ds_sellingEvidenceSave.setCellAllData(0, "costItemCd", acb_lc_costItemCd.getValue());

    ds_sellingEvidenceSave.setCellAllData(0, "trustClntNo", scwin.params.param13);//청구 거래처 번호
    ds_sellingEvidenceSave.setCellAllData(0, "trustCrn", scwin.params.param14); //사업자 번호
    ds_sellingEvidenceSave.setCellAllData(0, "drvNm", scwin.params.param15);
};

//close
scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};
